        # Randomly add/remove players
        if random.random() < 0.02 and len(self.game_state.players) < self.game_state.max_players:
            new_id = max((p.player_id for p in self.game_state.players), default=0) + 1
            name = ''.join(random.choices(string.ascii_letters, k=random.randint(5, 15)))
